import requests
from requests.auth import HTTPBasicAuth

# Configuration
KONG_ADMIN_URL = 'http://localhost:8001'
KONG_USERNAME = 'admin'
KONG_PASSWORD = 'password'

# Service configuration
SERVICE_NAME = 'my-service'
SERVICE_URL = 'http://example.com'

# Route configuration
ROUTE_PATH = '/api'
ROUTE_METHODS = ['GET', 'POST']

# Upstream configuration
UPSTREAM_NAME = 'my-upstream'
TARGET_HOST = 'target.example.com'
TARGET_PORT = 80

def create_service():
    url = f'{KONG_ADMIN_URL}/services'
    payload = {
        'name': SERVICE_NAME,
        'url': SERVICE_URL
    }
    response = requests.post(url, json=payload, auth=HTTPBasicAuth(KONG_USERNAME, KONG_PASSWORD))
    if response.status_code == 201:
        print(f'Service {SERVICE_NAME} created successfully')
        return response.json()['id']
    else:
        print(f'Failed to create service: {response.text}')
        return None

def create_route(service_id):
    url = f'{KONG_ADMIN_URL}/routes'
    payload = {
        'paths': [ROUTE_PATH],
        'methods': ROUTE_METHODS,
        'service': {'id': service_id}
    }
    response = requests.post(url, json=payload, auth=HTTPBasicAuth(KONG_USERNAME, KONG_PASSWORD))
    if response.status_code == 201:
        print(f'Route {ROUTE_PATH} created successfully')
        return response.json()['id']
    else:
        print(f'Failed to create route: {response.text}')
        return None

def create_upstream():
    url = f'{KONG_ADMIN_URL}/upstreams'
    payload = {
        'name': UPSTREAM_NAME
    }
    response = requests.post(url, json=payload, auth=HTTPBasicAuth(KONG_USERNAME, KONG_PASSWORD))
    if response.status_code == 201:
        print(f'Upstream {UPSTREAM_NAME} created successfully')
        return response.json()['id']
    else:
        print(f'Failed to create upstream: {response.text}')
        return None

def add_target_to_upstream(upstream_id):
    url = f'{KONG_ADMIN_URL}/upstreams/{upstream_id}/targets'
    payload = {
        'target': f'{TARGET_HOST}:{TARGET_PORT}'
    }
    response = requests.post(url, json=payload, auth=HTTPBasicAuth(KONG_USERNAME, KONG_PASSWORD))
    if response.status_code == 201:
        print(f'Target {TARGET_HOST}:{TARGET_PORT} added to upstream {UPSTREAM_NAME}')
    else:
        print(f'Failed to add target: {response.text}')

def main():
    service_id = create_service()
    if service_id:
        route_id = create_route(service_id)
        if route_id:
            upstream_id = create_upstream()
            if upstream_id:
                add_target_to_upstream(upstream_id)

if __name__ == '__main__':
    main()